# Test harness for GitHub Actions workflow validation
# Runs the workflow through act and validates output

param(
    [string] $WorkflowPath = "./.github/workflows/pr-label-assigner.yml",
    [string] $ResultFile = "./act-result.txt"
)

$ErrorActionPreference = "Stop"

# Helper function to run act and capture output
function Invoke-ActWorkflow {
    param(
        [string] $TempDir,
        [string[]] $ChangedFiles,
        [string] $TestName
    )

    Write-Host "Running test: $TestName"

    # Set up git repo with test files
    Push-Location $TempDir
    try {
        git init -q
        git config user.email "test@example.com"
        git config user.name "Test User"

        # Create and add files
        foreach ($file in $ChangedFiles) {
            $dir = Split-Path $file
            if ($dir) {
                New-Item -ItemType Directory -Path $dir -Force -ErrorAction SilentlyContinue | Out-Null
            }
            Set-Content -Path $file -Value "test content"
        }

        git add .
        git commit -m "Initial commit" -q

        # Copy workflow and scripts
        Copy-Item ".github" "." -Recurse -Force
        Copy-Item "src" "." -Recurse -Force
        Copy-Item "tests" "." -Recurse -Force
        Copy-Item "label-rules.json" "." -Force

        # Run act
        $output = act push --rm 2>&1
        return @{
            output = $output
            exitCode = $LASTEXITCODE
        }
    }
    finally {
        Pop-Location
    }
}

# Create results file
$resultsContent = @()
$resultsContent += "=== PR Label Assigner Test Results ==="
$resultsContent += "Test Date: $(Get-Date)"
$resultsContent += ""

# Test 1: Single file matching single rule
$test1Name = "Test 1: Single file - documentation label"
Write-Host "`nRunning $test1Name..."
$tempDir1 = New-Item -ItemType Directory -Path (Join-Path $env:TEMP "test-label-1") -Force
try {
    $result1 = Invoke-ActWorkflow -TempDir $tempDir1.FullName -ChangedFiles @("docs/README.md") -TestName $test1Name
    $resultsContent += "$test1Name"
    $resultsContent += "Exit Code: $($result1.exitCode)"
    if ($result1.exitCode -eq 0) {
        $resultsContent += "Status: PASSED"
    } else {
        $resultsContent += "Status: FAILED"
    }
    $resultsContent += "Output:"
    $resultsContent += $result1.output
    $resultsContent += ""
}
finally {
    Remove-Item $tempDir1.FullName -Recurse -Force -ErrorAction SilentlyContinue
}

# Test 2: File matching multiple rules
$test2Name = "Test 2: API file - multiple labels"
Write-Host "`nRunning $test2Name..."
$tempDir2 = New-Item -ItemType Directory -Path (Join-Path $env:TEMP "test-label-2") -Force
